55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	
62	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	};
68	
69	const INSURANCE_VALUES: Record<string, number> = {
70	  sword: 1000,
71	  amulet: 600,
72	  staff: 800,
73	  potion: 400,
74	  rune: 250,
75	  moonstone: 250,
76	};
77	
78	const DEDUCTIBLE = 100;
79	const CAP_MULTIPLIER = 2;
80	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
81	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
82	
83	const insuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;
84	const policyCap = (items: Item[]): number =>
85	  CAP_MULTIPLIER * items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
86	
87	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
88	  rune: 25,
89	  moonstone: 25,
90	};
91	
92	const ITEM_BASE_PREMIUMS: Record<string, number> = {
93	  ...MAIN_ITEM_BASE_PREMIUMS,
94	  ...COMPONENT_BASE_PREMIUMS,
95	};
96	
97	const COMPONENT_TYPES = new Set(Object.keys(COMPONENT_BASE_PREMIUMS));
98	const BLOCK_SIZE = 3;
99	const BLOCK_BASE = 60;
100	
101	const CURSE_SURCHARGE_RATE = 0.5;
102	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
103	const HIGH_ENCHANTMENT_THRESHOLD = 5;
104	const LOYALTY_DISCOUNT_RATE = 0.2;
105	const LOYALTY_THRESHOLD_YEARS = 2;
106	const FOLLOWUP_DISCOUNT_RATE = 0.15;
107	
108	const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;
109	
110	const componentGroupBase = (count: number, unitBase: number): number => {
111	  if (count === BLOCK_SIZE) return BLOCK_BASE;
112	  return count * unitBase;
113	};
114	
115	const itemSurchargeRate = (item: Item): number => {
116	  let rate = 0;
117	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
118	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
119	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
120	  }
121	  return rate;
122	};
123	
124	const itemSurcharge = (item: Item, base: number): number =>
125	  base * itemSurchargeRate(item);
126	
127	const policyModifierRate = (customer: Customer, priorQuoteCount: number): number => {
128	  let rate = FIRST_INSURANCE_SURCHARGE_RATE;
129	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
130	    rate -= LOYALTY_DISCOUNT_RATE;
131	  }
132	  if (priorQuoteCount >= 1) {
133	    rate -= FOLLOWUP_DISCOUNT_RATE;
134	  }
135	  return rate;
136	};
137	
138	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
139	
140	const componentsBaseTotal = (components: Item[]): number => {
141	  const counts = new Map<string, number>();
142	  for (const item of components) {
143	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
144	  }
145	  let total = 0;
146	  for (const [type, count] of counts) {
147	    total += componentGroupBase(count, itemBase(type));
148	  }
149	  return total;
150	};
151	
152	const mainItemsBaseTotal = (mainItems: Item[]): number =>
153	  mainItems.reduce((sum, item) => sum + itemBase(item.type), 0);
154	
155	const mainItemsSurchargeTotal = (mainItems: Item[]): number =>
156	  mainItems.reduce((sum, item) => sum + itemSurcharge(item, itemBase(item.type)), 0);
157	
158	const quotePremium = (items: Item[], customer: Customer, priorQuoteCount: number): number => {
159	  const mainItems = items.filter((item) => !isComponent(item));
160	  const components = items.filter(isComponent);
161	
162	  const policyBase = mainItemsBaseTotal(mainItems) + componentsBaseTotal(components);
163	  const itemSurchargeTotal = mainItemsSurchargeTotal(mainItems);
164	  const policyModifierTotal = policyBase * policyModifierRate(customer, priorQuoteCount);
165	
166	  const total = policyBase + itemSurchargeTotal + policyModifierTotal;
167	  return roundUp(total) + PROCESSING_FEE;
168	};
169	
170	const reimbursableAmount = (insuredItem: Item, damageAmount: number): number => {
171	  if ((insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
172	    return damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE;
173	  }
174	  return damageAmount;
175	};
176	
177	const damagePayout = (damage: Damage, insuredItem: Item): number =>
178	  Math.max(0, reimbursableAmount(insuredItem, damage.amount) - DEDUCTIBLE);
179	
180	const findInsuredItem = (items: Item[], itemType: string): Item =>
181	  items.find((item) => item.type === itemType) as Item;
182	
183	const totalPayout = (damages: Damage[], items: Item[]): number =>
184	  damages.reduce(
185	    (sum, damage) => sum + damagePayout(damage, findInsuredItem(items, damage.itemType)),
186	    0,
187	  );
188	
189	const policyItems = (scenario: Scenario, policyIndex: number): Item[] =>
190	  (scenario.steps[policyIndex] as QuoteStep).items;
191	
192	const processClaim = (step: ClaimStep, scenario: Scenario): ClaimResult => {
193	  const items = policyItems(scenario, step.policy);
194	  const cap = policyCap(items);
195	  const payout = totalPayout(step.incident.damages, items);
196	  return { payout, remainingCap: cap - payout };
197	};
198	
199	const processStep = (
200	  step: Step,
201	  scenario: Scenario,
202	  priorQuoteCount: number,
203	): StepResult => {
204	  if (step.op === "quote") {
205	    return { premium: quotePremium(step.items, scenario.customer, priorQuoteCount) };
206	  }
207	  return processClaim(step, scenario);
208	};
209	
210	export const processScenario = (scenario: Scenario): ScenarioResult => {
211	  let priorQuoteCount = 0;
212	  const results: StepResult[] = scenario.steps.map((step) => {
213	    const result = processStep(step, scenario, priorQuoteCount);
214	    if (step.op === "quote") priorQuoteCount++;
215	    return result;
216	  });
217	  return { results };
218	};
